with open(hadith_path, "r", encoding="utf-8") as f:
    hadith_db = json.load(f)

# find if any hadith contains "تبذر"
def find_in_hadith(term):
    hits = []
    for h in hadith_db:
        for key in ('hadithTxt', 'Matn'):
            if key in h and isinstance(h[key], str):
                if term in h[key]:
                    hits.append(h)
                    break
    return hits

